const fs = require\('fs'\);
const data = JSON.parse\(fs.readFileSync\('data/products.json', 'utf8'\)\);

// Define print area by garment type / product characteristics
const areas = {
  // All-over-print tees - image covers most of the front
  'all-over-tee': { top_pct: 8, left_pct: 8, width_pct: 84, height_pct: 84 },
  // DTG tee \(gildan\) - defined print area on chest
  'dtg-tee': { top_pct: 20, left_pct: 22, width_pct: 56, height_pct: 45 },
  // Polo embroidery - small chest area
  'embroidery-chest': { top_pct: 25, left_pct: 15, width_pct: 25, height_pct: 15 },
  // Hoodie all-over
  'hoodie': { top_pct: 12, left_pct: 10, width_pct: 80, height_pct: 76 },
  // Leggings - tall narrow
  'leggings': { top_pct: 5, left_pct: 15, width_pct: 70, height_pct: 90 },
  // Shorts
  'shorts': { top_pct: 10, left_pct: 10, width_pct: 80, height_pct: 80 },
  // Dress
  'dress': { top_pct: 8, left_pct: 12, width_pct: 76, height_pct: 84 },
  // Swimwear
  'swimsuit': { top_pct: 8, left_pct: 10, width_pct: 80, height_pct: 84 },
  // Tote / bags
  'tote': { top_pct: 10, left_pct: 10, width_pct: 80, height_pct: 80 },
  'backpack': { top_pct: 10, left_pct: 15, width_pct: 70, height_pct: 75 },
  'crossbody': { top_pct: 10, left_pct: 10, width_pct: 80, height_pct: 80 },
  'duffle': { top_pct: 15, left_pct: 10, width_pct: 80, height_pct: 70 },
  'gym': { top_pct: 10, left_pct: 10, width_pct: 80, height_pct: 80 },
  // Hats
  'bucket-hat': { top_pct: 15, left_pct: 15, width_pct: 70, height_pct: 55 },
  'embroidery-hat': { top_pct: 25, left_pct: 20, width_pct: 60, height_pct: 35 },
  // Phone case
  'phone-case': { top_pct: 8, left_pct: 12, width_pct: 76, height_pct: 84 },
  // Poster - full area
  'poster': { top_pct: 5, left_pct: 5, width_pct: 90, height_pct: 90 },
  // Mug
  'mug': { top_pct: 15, left_pct: 10, width_pct: 80, height_pct: 70 },
};

function getArea\(p\) {
  const key = p.product_key;
  if \(key === 'gildan-5000'\) return areas['dtg-tee'];
  if \(p.placement === 'embroidery_chest_left'\) return areas['embroidery-chest'];
  if \(p.placement === 'embroidery_front_large'\) return areas['embroidery-hat'];
  if \(key.includes\('bucket-hat'\)\) return areas['bucket-hat'];
  if \(key.includes\('backpack'\)\) return areas['backpack'];
  if \(key.includes\('crossbody'\)\) return areas['crossbody'];
  if \(key.includes\('duffle'\)\) return areas['duffle'];
  if \(key.includes\('gym-bag'\)\) return areas['gym'];
  if \(key.includes\('tote'\)\) return areas['tote'];
  if \(key.includes\('legging'\)\) return areas['leggings'];
  if \(key.includes\('short'\)\) return areas['shorts'];
  if \(key.includes\('hoodie'\)\) return areas['hoodie'];
  if \(key.includes\('dress'\)\) return areas['dress'];
  if \(key.includes\('swimsuit'\) || key.includes\('swim-trunk'\)\) return areas['swimsuit'];
  if \(key.includes\('snap-case'\) || key.includes\('iphone'\)\) return areas['phone-case'];
  if \(key.includes\('poster'\)\) return areas['poster'];
  if \(key.includes\('mug'\)\) return areas['mug'];
  if \(p.garment_type === 'camiseta'\) return areas['all-over-tee'];
  return areas['all-over-tee']; // fallback
}

data.products.forEach\(p => {
  p.preview_print_area = getArea\(p\);
}\);

fs.writeFileSync\('data/products.json', JSON.stringify\(data, null, 2\) + '\\n'\);
console.log\('Done. Added preview_print_area to all', data.products.length, 'products'\);
")
